sed -i '/id: '\''math5-q3'\''/,/points: 15/{n; n; n; a\      },\n      {\n        id: '\''math5-q4'\'',\n        question: '\''Вычисли: 5² - 3²'\'',\n        options: ['\''16'\'', '\''4'\'', '\''2'\'', '\''34'\''],\n        correctAnswer: 0,\n        explanation: '\''5² - 3² = 25 - 9 = 16. Сначала возводим в степень, потом вычитаем.'\'',\n        difficulty: '\''medium'\'',\n        points: 15\n      },\n      {\n        id: '\''math5-q5'\'',\n        question: '\''Какое число в квадрате даёт 36?'\'',\n        options: ['\''5'\'', '\''6'\'', '\''18'\'', '\''9'\''],\n        correctAnswer: 1,\n        explanation: '\''6² = 36. Квадрат числа — это число, умноженное само на себя.'\'',\n        difficulty: '\''easy'\'',\n        points: 10\n      },\n      {\n        id: '\''math5-q6'\'',\n        question: '\''Приведи дробь 3/4 к знаменателю 12'\'',\n        question: '\''Приведи дробь 3/4 к знаменателю 12'\'',\n        options: ['\''6/12'\'', '\''9/12'\'', '\''3/12'\'', '\''12/12'\''],\n        correctAnswer: 1,\n        explanation: '\''3/4 = (3×3)/(4×3) = 9/12. Умножаем числитель и знаменатель на 3.'\'',\n        difficulty: '\''medium'\'',\n        points: 15\n      },\n      {\n        id: '\''math5-q7'\'',\n        question: '\''Найди НОД чисел 12 и 18'\'',\n        options: ['\''2'\'', '\''3'\'', '\''6'\'', '\''36'\''],\n        correctAnswer: 2,\n        explanation: '\''НОД(12,18) = 6. Это наибольшее число, на которое делятся оба числа.'\'',\n        difficulty: '\''medium'\'',\n        points: 15\n      },\n      {\n        id: '\''math5-q8'\'',\n        question: '\''Вычисли: 2³'\'',\n        options: ['\''6'\'', '\''5'\'', '\''8'\'', '\''9'\''],\n        correctAnswer: 2,\n        explanation: '\''2³ = 2 × 2 × 2 = 8. Куб числа — это трижды умноженное число на себя.'\'',\n        difficulty: '\''easy'\'',\n        points: 10\n      },\n      {\n        id: '\''math5-q9'\'',\n        question: '\''Какой треугольник имеет все стороны равные?'\'',\n        options: ['\''Разносторонний'\'', '\''Равнобедренный'\'', '\''Равносторонний'\'', '\''Прямоугольный'\''],\n        correctAnswer: 2,\n        explanation: '\''Равносторонний треугольник имеет три равные стороны и три угла по 60°.'\'',\n        difficulty: '\''easy'\'',\n        points: 10\n      },\n      {\n        id: '\''math5-q10'\'',\n        question: '\''Сумма углов треугольника равна:'\'',\n        options: ['\''90°'\'', '\''180°'\'', '\''360°'\'', '\''270°'\''],\n        correctAnswer: 1,\n        explanation: '\''Сумма углов любого треугольника всегда равна 180°.'\'',\n        difficulty: '\''medium'\'',\n        points: 15\n      },\n      {\n        id: '\''math5-q11'\'',\n        question: '\''Вычисли: 15 + 27 - 12'\'',\n        options: ['\''20'\'', '\''30'\'', '\''40'\'', '\''25'\''],\n        correctAnswer: 1,\n        explanation: '\''15 + 27 - 12 = 42 - 12 = 30. Сложение и вычитание выполняем слева направо.'\'',\n        difficulty: '\''easy'\'',\n        points: 10\n      },\n      {\n        id: '\''math5-q12'\'',\n        question: '\''Какое число является делителем 24?'\'',\n        options: ['\''5'\'', '\''7'\'', '\''8'\'', '\''9'\''],\n        correctAnswer: 2,\n        explanation: '\''24 ÷ 8 = 3. Число 8 является делителем 24, так как делится на него без остатка.'\'',\n        difficulty: '\''easy'\'',\n        points: 10\n      },\n      {\n        id: '\''math5-q13'\'',\n        question: '\''Найди периметр квадрата со стороной 5 см'\'',\n        options: ['\''10 см'\'', '\''15 см'\'', '\''20 см'\'', '\''25 см'\''],\n        correctAnswer: 2,\n        explanation: '\''P = 4 × a = 4 × 5 = 20 см. Периметр квадрата — это сумма всех четырёх сторон.'\'',\n        difficulty: '\''easy'\'',\n        points: 10
}' /home/z/my-project/src/data/grade5-class.tsx

